INSERT INTO `area` (`id`, `name`, `description`, `lat`, `lng`, `image`, `createdAt`, `updatedAt`) VALUES
(1, 'Denpasar Area', 'Denpasar, Bali’s vibrant capital city, serves as the administrative and commercial hub of the island. This bustling area offers a mix of traditional Balinese culture and modern amenities, including markets, temples, shopping centers, and a variety of dining options. Whether you’re arriving at Ngurah Rai International Airport or staying in the heart of Denpasar, this area is a convenient and central pickup point for exploring the southern regions of Bali.', -8.65, 115.217, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567062/baliholiday/areas/v0mhtkvntsmeoosz5za7.webp', '2024-12-11 14:03:37', '2024-12-13 07:36:03'),
(2, 'Ngurah Rai International Airport', 'Ngurah Rai International Airport is Bali’s primary gateway, handling millions of visitors each year. Located in Tuban, close to Kuta and Seminyak, the airport is well-equipped with modern facilities and transportation options. As the main entry point to the island, it serves as a crucial pickup location for tourists arriving from around the world, ensuring seamless transfers to various parts of Bali.', -8.74645, 115.168, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567064/baliholiday/areas/ussdy7um0iecjyalxbwz.webp', '2024-12-11 14:13:49', '2024-12-13 16:08:53'),
(3, 'Legian Area', 'Legian is a lively beachfront area situated between Kuta and Seminyak, renowned for its vibrant nightlife, bustling markets, and diverse dining scene. The long stretch of Legian Beach is perfect for sunbathing, surfing, and enjoying stunning sunsets. With numerous hotels, resorts, and entertainment venues, Legian is a popular pickup location for travelers seeking both relaxation and excitement.', -8.70561, 115.169, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567065/baliholiday/areas/xzgxfp69kc6xuutzasmf.webp', '2024-12-13 07:55:19', '2024-12-13 07:55:19'),
(4, 'Seminyak Area', 'Seminyak is Bali’s upscale destination, famous for its sophisticated ambiance, high-end boutiques, chic beach clubs, and gourmet restaurants. The elegant Seminyak Beach offers serene sunrises and spectacular sunsets, making it an ideal spot for both leisure and photography. As a prime area for luxury accommodations, Seminyak serves as a premier pickup point for guests looking to experience Bali’s finer side.', -8.69055, 115.159, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567067/baliholiday/areas/uoeuqkc3wx8qq65b3vfa.webp', '2024-12-13 08:03:26', '2024-12-13 08:03:26'),
(5, 'Kuta Area', 'Kuta is one of Bali’s most iconic areas, celebrated for its bustling nightlife, extensive shopping options, and the famous Kuta Beach known for its lively atmosphere and excellent surfing conditions. This area is perfect for travelers seeking a dynamic and energetic environment. With numerous hotels, hostels, and entertainment venues, Kuta is a key pickup location for those wanting to immerse themselves in Bali’s vibrant scene.', -8.72254, 115.175, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567069/baliholiday/areas/oqqyul6ckkmy2egnxjh5.webp', '2024-12-13 08:05:06', '2024-12-13 08:05:06'),
(6, 'Jimbaran Area', 'Jimbaran is renowned for its stunning beaches and world-class seafood restaurants lining the shore. This tranquil area offers a more relaxed atmosphere compared to the bustling beaches of Kuta and Seminyak. Jimbaran Bay is perfect for romantic dinners, beachside relaxation, and enjoying picturesque sunsets. It serves as an excellent pickup point for visitors seeking a peaceful and scenic start to their Bali adventures.', -8.78582, 115.166, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567071/baliholiday/areas/m1qwgfziet0gwk1ccibo.webp', '2024-12-13 08:08:57', '2024-12-13 08:08:57'),
(7, 'Uluwatu', 'Uluwatu is famed for its dramatic cliffside views, iconic temples, and some of Bali’s best surf spots. The Uluwatu Temple, perched atop a limestone cliff, offers breathtaking panoramic views of the Indian Ocean and is a must-visit cultural landmark. This area is ideal for travelers looking to explore Bali’s natural beauty and spiritual heritage, making it a unique pickup location for adventure and culture enthusiasts.', -8.82755, 113.088, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567073/baliholiday/areas/yacak15mwwetew3tacxb.webp', '2024-12-13 08:11:58', '2024-12-13 08:11:58'),
(8, 'Nusa Dua Area', 'Nusa Dua is Bali’s premier luxury resort area, known for its pristine beaches, upscale hotels, and meticulously maintained gardens. The calm waters and soft sands of Nusa Dua Beach make it perfect for swimming, sunbathing, and water sports. This area is ideal for families and travelers seeking a serene and sophisticated environment, making it a prime pickup location for those staying in luxury accommodations.', -8.79629, 115.228, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567075/baliholiday/areas/fis6ot0ajjmj3zksvmel.webp', '2024-12-13 08:17:16', '2024-12-13 08:17:16'),
(9, ' Canggu Area', 'Canggu is a trendy coastal town located on Bali\'s southern shores, known for its laid-back vibe, surf-friendly beaches, and vibrant expat community. Over the years, it has evolved into a hub for digital nomads, creatives, and tourists seeking a blend of modern conveniences and natural beauty. The area offers an eclectic mix of beach clubs, chic cafés, yoga studios, and boutique shops, all nestled amidst lush rice paddies and scenic ocean views. With its growing reputation as a hotspot for both relaxation and adventure, Canggu combines the best of Bali\'s laid-back lifestyle with a lively, cosmopolitan atmosphere.', -8.65165, 115.134, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567077/baliholiday/areas/ksssbqh1wmm30byuyfrf.webp', '2024-12-13 08:21:24', '2024-12-13 08:21:24'),
(11, 'Sanur Area', 'Sanur, located on the southeastern coast of Bali, is a charming and peaceful beach town known for its serene atmosphere and beautiful coastline. Unlike the bustling areas of Bali, Sanur offers a more relaxed and traditional vibe, making it ideal for families and those looking to unwind. The long stretch of sandy beach is perfect for swimming, walking, and enjoying stunning sunrises. Along the waterfront, you\'ll find a blend of seaside cafés, restaurants, and local shops, offering a taste of Balinese culture. Sanur is also home to vibrant coral reefs, making it a great spot for snorkeling and water sports. With its mix of natural beauty, cultural richness, and quieter pace, Sanur remains a beloved destination for those seeking an authentic Bali experience.', -8.70539, 115.26, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567080/baliholiday/areas/yrosjjejzgyh7ofvfb7j.webp', '2024-12-13 08:24:40', '2024-12-13 08:24:40'),
(12, 'Ubud Area', 'Ubud is the cultural heart of Bali, surrounded by lush rice terraces, ancient temples, and vibrant art scenes. Known for its rich heritage, Ubud offers a blend of traditional and contemporary attractions, including art galleries, handicraft markets, and wellness retreats. The town is a haven for travelers seeking spiritual enrichment, artistic inspiration, and natural beauty, making it a key pickup location for those looking to immerse themselves in Bali’s cultural essence.', -8.50688, 115.262, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567082/baliholiday/areas/jzarxbxzocvdflxwadl4.webp', '2024-12-13 08:37:15', '2024-12-13 08:37:15'),
(13, 'Sukawati Area', 'Sukawati, located in the Gianyar Regency of Bali, is a cultural and artistic hub that offers a glimpse into traditional Balinese life. Known for its vibrant art scene, Sukawati is home to numerous galleries and local markets where visitors can find handcrafted paintings, sculptures, and textiles made by talented local artisans. The area is also famous for the Sukawati Art Market, where shoppers can explore an array of unique, handmade crafts and souvenirs. Surrounded by lush rice paddies and scenic landscapes, Sukawati provides a peaceful and immersive atmosphere that contrasts with the more tourist-heavy regions of Bali. It\'s a perfect destination for those seeking an authentic cultural experience, away from the crowds, while still being close to popular attractions like Ubud and its rice terraces.', -8.60421, 115.281, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567084/baliholiday/areas/vt3gzgb8z66xhxtybgjp.webp', '2024-12-13 08:43:20', '2024-12-13 08:43:20'),
(14, 'Amed Area', 'Amed is a tranquil coastal region in eastern Bali, known for its stunning black sand beaches, vibrant coral reefs, and excellent diving and snorkeling opportunities. The area is less crowded than the southern beaches, offering a peaceful retreat with picturesque views and a laid-back atmosphere. Amed serves as an ideal pickup location for travelers seeking underwater adventures, relaxation, and authentic Balinese village experiences.', -8.33472, 115.65, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567086/baliholiday/areas/aku7o4vo3zfb7zmcw2pg.webp', '2024-12-13 08:46:54', '2024-12-13 08:46:54'),
(15, 'Padangbai Area', 'Padangbai is a key port town in eastern Bali, serving as the main gateway for ferries to Lombok and other nearby islands. It boasts beautiful beaches, such as Blue Lagoon Beach and Tanjung Jepun, which are perfect for swimming, snorkeling, and enjoying the coastal scenery. With its strategic location and transportation links, Padangbai is a convenient pickup point for both incoming and outgoing travelers exploring eastern Bali and beyond.', -8.53054, 115.51, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567089/baliholiday/areas/onogfdosxk3cexrbn8ul.webp', '2024-12-13 08:49:00', '2024-12-13 08:49:00'),
(16, 'Karangasem Area', 'Karangasem is a picturesque region in eastern Bali, home to some of the island’s most significant cultural and natural attractions. Highlights include the majestic Besakih Temple, known as the \"Mother Temple\" of Bali, and the stunning Tirta Gangga Water Palace, famous for its intricate water gardens and fountains. This area is perfect for travelers interested in exploring Bali’s spiritual sites and breathtaking landscapes, making it a valuable pickup location for cultural and nature tours.', -8.44296, 115.611, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567091/baliholiday/areas/dlczootvojo6sbgkjgac.webp', '2024-12-13 15:03:40', '2024-12-13 15:03:40'),
(17, 'Sidemen Area', 'Sidemen is a serene valley located in the Karangasem region, celebrated for its lush rice terraces, traditional villages, and scenic beauty. This area offers a peaceful escape from the tourist crowds, providing opportunities for trekking, cycling, and experiencing authentic Balinese rural life. Sidemen serves as an excellent pickup point for visitors looking to explore Bali’s natural landscapes and immerse themselves in its cultural heritage.', -8.46232, 115.444, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567093/baliholiday/areas/oruxqkea0cbgvoa40xuj.webp', '2024-12-13 15:06:46', '2024-12-13 15:06:46'),
(18, 'Lovina Area', 'Lovina is a charming coastal town in northern Bali, famous for its calm seas, black sand beaches, and dolphin-watching tours. The area offers a relaxed atmosphere with a range of accommodations, from budget hostels to luxury resorts. Lovina’s serene beaches and unique marine life make it a popular pickup location for travelers seeking a peaceful coastal retreat and unforgettable dolphin encounters.', -8.15891, 115.03, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567095/baliholiday/areas/fxwmnew5fet4nqb73lri.webp', '2024-12-13 15:10:02', '2024-12-13 15:10:02'),
(19, 'Munduk Area', 'Munduk is a picturesque village in northern Bali, renowned for its stunning waterfalls, lush coffee plantations, and cool mountain climate. The area is perfect for nature enthusiasts and adventure seekers, offering numerous hiking trails, scenic viewpoints, and opportunities to explore Bali’s rich biodiversity. Munduk serves as an ideal pickup point for those looking to experience Bali’s natural beauty and tranquil countryside.', -8.25269, 115.079, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567097/baliholiday/areas/opfzcxrr97cnzxtt9qc3.webp', '2024-12-13 15:12:58', '2024-12-13 15:12:58'),
(20, 'Pemuteran Area', 'Pemuteran is a serene coastal village in northern Bali, known for its beautiful beaches, coral reefs, and the nearby Menjangan Island, part of the West Bali National Park. The area is a haven for divers and snorkelers, offering some of Bali’s best underwater experiences. Pemuteran serves as a key pickup point for eco-tourists and adventure seekers looking to explore Bali’s marine life and pristine natural environments.', -8.14033, 114.658, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567098/baliholiday/areas/l87brvqelgb5pxkdzsqn.webp', '2024-12-13 15:19:08', '2024-12-13 15:19:08'),
(21, 'Singaraja Area', 'Singaraja is the second-largest city in Bali, located in the northern part of the island. Historically the capital of Bali, Singaraja boasts a blend of colonial architecture, vibrant markets, and cultural landmarks. The city serves as a gateway to northern Bali’s attractions, including waterfalls, temples, and natural reserves, making it a convenient pickup location for travelers exploring this less-visited region of Bali.', -8.11434, 115.08, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567100/baliholiday/areas/v4w2ont30bxkhq9gdusz.webp', '2024-12-13 15:21:17', '2024-12-13 15:21:17'),
(22, 'Tanah Lot Area', 'Tanah Lot is one of Bali’s most famous and picturesque temples, perched on a rocky outcrop overlooking the Indian Ocean. Renowned for its stunning sunsets and cultural significance, Tanah Lot is a must-visit landmark that embodies Bali’s spiritual heritage. The surrounding area offers beautiful coastal views and is a popular pickup location for visitors eager to experience Bali’s iconic temple and scenic landscapes.', -8.61575, 115.091, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567102/baliholiday/areas/xjwfocubtis3kasaf2gt.webp', '2024-12-13 15:24:59', '2024-12-13 15:24:59'),
(23, 'Seseh Area', 'Seseh is a tranquil coastal village in western Bali, known for its peaceful beaches, traditional fishing villages, and lush greenery. The area offers a more laid-back and authentic Balinese experience, away from the bustling tourist spots. Seseh serves as an excellent pickup point for travelers seeking relaxation, cultural exploration, and beautiful natural surroundings in western Bali.', -8.61654, 115.128, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567104/baliholiday/areas/yls30dfsqmx3pdeyo9ky.webp', '2024-12-13 15:38:28', '2024-12-13 15:38:28'),
(24, 'Padangbai Port', 'Padangbai Port is a major ferry terminal in eastern Bali, providing essential links to Lombok and other nearby islands. It is a bustling hub for both passenger and cargo traffic, making it an important transportation point for travelers and goods. Padangbai Port serves as a convenient pickup location for those embarking on inter-island travels or exploring the eastern regions of Bali, offering easy access to various coastal attractions and transportation services.', -8.53378, 115.509, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567106/baliholiday/areas/ydwzgi6t8bj614faovmw.webp', '2024-12-13 15:40:17', '2024-12-13 15:40:17'),
(25, 'Kerobokan Area', 'Kerobokan is a vibrant area located between Seminyak and Canggu, known for its eclectic mix of restaurants, bars, and boutique shops. Jalan Raya Kerobokan, the main street, is lined with a variety of accommodations ranging from luxury villas to budget-friendly hotels. This area is popular among expatriates and tourists alike, making it a convenient pickup location for those staying in Kerobokan and nearby neighborhoods.', -8.6532, 115.168, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567108/baliholiday/areas/ga3nf7pyanmw1q4eebhf.webp', '2024-12-13 15:45:32', '2024-12-13 16:12:41');

