INSERT INTO `destinations` (`id`, `name`, `description`, `lat`, `lng`, `image`, `createdAt`, `updatedAt`) VALUES
(1, 'Ubud Monkey Forest', 'The Sacred Monkey Forest Sanctuary, also known as Ubud Monkey Forest, is a renowned nature reserve and Hindu temple complex located in Ubud. The sanctuary is home to over 700 long-tailed macaques that roam freely among the ancient temples, statues, and lush greenery. Visitors can explore the sacred grounds, observe the playful monkeys, and appreciate the serene and spiritual ambiance of the forest. The Monkey Forest is a popular destination for families, nature lovers, and those interested in Balinese culture and wildlife.\r\n', -8.5192, 115.261, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567110/baliholiday/destinations/isdplohzxo18uvjvxf3q.webp', '2024-12-10 16:35:39', '2024-12-21 05:19:29'),
(5, 'Tanah Lot', 'Tanah Lot Temple is one of Bali\'s most photographed landmarks, situated on a rocky outcrop in the sea. This ancient Hindu temple is best visited during sunset, when the sky and sea create a breathtaking backdrop. Tanah Lot is deeply rooted in Balinese mythology and offers visitors a glimpse into the island\'s rich cultural heritage, making it a must-visit destination for both its scenic beauty and spiritual importance.\r\n', -8.62105, 115.087, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567112/baliholiday/destinations/ixselogxjsraxnbrcbpd.webp', '2024-12-11 17:27:56', '2024-12-20 05:56:57'),
(6, 'Kuta Beach', 'Kuta Beach is one of Bali\'s most famous and bustling beaches, renowned for its long stretch of golden sand and vibrant sunset views. It\'s a hotspot for surfers, especially beginners, and offers a lively atmosphere with numerous bars, restaurants, and shops lining the shore. The beach is also famous for its vibrant nightlife and bustling market areas, making it a favorite among tourists seeking both relaxation and entertainment.\r\n', -8.71799, 115.167, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567113/baliholiday/destinations/hizmpue1vfx2x8ih38xw.webp', '2024-12-11 17:52:24', '2024-12-20 05:55:04'),
(7, 'Seminyak Beach', 'Seminyak Beach is celebrated for its upscale ambiance, trendy beach clubs, and sophisticated dining options. The beach boasts a more refined and less crowded atmosphere compared to Kuta, attracting visitors looking for a luxurious beach experience. With stunning sunsets, stylish resorts, and excellent shopping boutiques nearby, Seminyak is perfect for those seeking a blend of relaxation and high-end leisure.\r\n', -8.69163, 115.157, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567115/baliholiday/destinations/ongsywsy7b4xz1fsvel9.webp', '2024-12-20 05:23:24', '2024-12-20 05:23:24'),
(8, 'Nusa Dua Beach', 'Nusa Dua Beach is renowned for its pristine white sands, calm waters, and meticulously maintained surroundings. This beach area is home to some of Bali\'s most luxurious resorts and is ideal for families and travelers seeking a tranquil and secure environment. The clear waters are perfect for swimming, snorkeling, and various water sports, while the well-kept beaches ensure a comfortable and enjoyable visit.\r\n', -8.79556, 115.233, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567117/baliholiday/destinations/f40cvyb6lsik35ir9nit.webp', '2024-12-20 05:38:27', '2024-12-20 05:38:27'),
(9, 'Jimbaran Beach', 'Jimbaran Beach is famous for its serene ambiance and stunning sunset views over the Indian Ocean. It\'s particularly well-known for its seafood restaurants that line the beach, offering fresh catches grilled to perfection right on the sand. The gentle waves make it a great spot for swimming and relaxation, while the picturesque setting provides a romantic backdrop for evening dining.\r\n', -8.77225, 115.169, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567119/baliholiday/destinations/ofibf3nj0qwdrryp7ib1.webp', '2024-12-20 05:48:16', '2024-12-20 05:48:16'),
(10, 'Sanur Beach', 'Sanur Beach offers a laid-back and family-friendly atmosphere with its calm, shallow waters and long promenade. This beach is perfect for leisurely walks, cycling, and enjoying water activities such as paddleboarding and kayaking. Sanur retains a traditional Balinese charm with its nearby temples and local villages, providing a peaceful escape from the more crowded tourist areas.', -8.67345, 115.264, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567121/baliholiday/destinations/cmgetcsxir8zt2afbcnl.webp', '2024-12-20 05:51:12', '2024-12-20 05:51:12'),
(11, 'Padang Padang Beach', 'Padang Padang Beach is a hidden gem known for its unique rock formations and clear turquoise waters. This beach gained fame from the movie \"Eat Pray Love\" and is a popular spot for surfers due to its consistent waves. The picturesque setting, with its surrounding cliffs and caves, makes it a favorite for both adventure seekers and those looking to relax in a scenic environment.\r\n', -8.81092, 115.104, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567124/baliholiday/destinations/k2pv3gl92l8mtkt5eisp.webp', '2024-12-20 05:53:45', '2024-12-20 05:53:45'),
(12, 'Balangan Beach', 'Balangan Beach is a secluded paradise offering stunning panoramic views and a tranquil atmosphere. With its soft white sands and crystal-clear waters, it\'s an ideal spot for sunbathing, swimming, and surfing. The beach is framed by dramatic cliffs and lush greenery, providing a perfect backdrop for relaxation and photography enthusiasts alike.\r\n', -8.79194, 115.123, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567126/baliholiday/destinations/b3zjcvauobhcgaed0kku.webp', '2024-12-20 06:02:54', '2024-12-20 06:02:54'),
(13, 'Dreamland Beach ', 'Dreamland Beach captivates visitors with its expansive shoreline, dramatic rock formations, and vibrant surf culture. The beach\'s consistent waves make it a favorite among surfers, while its wide sandy area is perfect for sunbathing and beach games. The stunning sunsets and scenic beauty add to the beach\'s allure, making it a must-visit destination for both adventure and leisure.\r\n', -8.79925, 115.118, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567128/baliholiday/destinations/tvop6fl9q5xzjfnzhcda.webp', '2024-12-21 03:52:24', '2024-12-21 03:52:24'),
(14, 'Blue Lagoon Beach', 'Blue Lagoon Beach is celebrated for its stunning blue waters and rich marine life, making it a prime spot for snorkeling and diving. The beach\'s sheltered bay provides calm waters ideal for swimming and exploring the vibrant coral reefs. Surrounded by lush vegetation and dramatic cliffs, Blue Lagoon offers a picturesque setting for nature lovers and water sports enthusiasts.\r\n', -8.52937, 115.513, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567130/baliholiday/destinations/pjldhcfm7zriajc0rr9s.webp', '2024-12-21 04:19:37', '2024-12-21 04:19:37'),
(15, 'Amed Beach', 'Amed Beach is a tranquil and less commercialized beach area known for its black volcanic sands and excellent diving spots. The clear waters are home to vibrant coral reefs and diverse marine life, attracting snorkelers and scuba divers from around the world. Amed\'s peaceful environment, traditional fishing villages, and stunning underwater landscapes make it a perfect destination for those seeking a serene and authentic Bali experience.', -8.3352, 115.658, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567132/baliholiday/destinations/drp3s6mdbidi1osstm8n.webp', '2024-12-21 04:25:00', '2024-12-21 05:11:22'),
(16, 'Lovina Beach', 'Lovina Beach is famous for its calm seas, black sand beaches, and captivating dolphin sightings at sunrise. Located on Bali\'s north coast, Lovina offers a peaceful retreat with its laid-back vibe and scenic landscapes. Visitors can enjoy dolphin tours, snorkeling, and exploring nearby hot springs and waterfalls, making it a versatile destination for both relaxation and adventure.\r\n', -8.1604, 115.03, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567136/baliholiday/destinations/rmzcnceb6v752qcb3vzv.webp', '2024-12-21 04:33:02', '2024-12-21 05:09:22'),
(17, 'Canggu Beach', 'Canggu Beach is a trendy hotspot popular among surfers, digital nomads, and young travelers. The beach is known for its consistent waves, vibrant street art, and eclectic cafes and bars. Canggu\'s lively and creative atmosphere, combined with its beautiful beaches and scenic rice fields, makes it a favorite destination for those seeking a blend of surf culture, modern amenities, and natural beauty.\r\n', -8.66092, 115.132, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567138/baliholiday/destinations/bz1wc4cdbb4b4uezt7jf.webp', '2024-12-21 04:41:23', '2024-12-21 05:12:56'),
(18, 'Bingin Beach', 'Bingin Beach is a picturesque beach known for its stunning sunsets, white sands, and excellent surf breaks. The beach is framed by dramatic cliffs and lush greenery, offering a serene and scenic environment. Bingin is less crowded than some of Bali\'s more popular beaches, providing a peaceful escape for sunbathers, surfers, and those looking to enjoy the natural beauty of Bali\'s coastline.\r\n', -8.8055, 115.113, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567141/baliholiday/destinations/g3lpjtfaesbrjdfoqtqu.webp', '2024-12-21 05:07:43', '2024-12-21 05:07:43'),
(19, 'Seseh Beach', ' Seseh Beach offers a quiet and unspoiled beach experience with its expansive sandy shores and calm waters. Located in a serene part of Bali, Seseh is perfect for long walks, picnics, and relaxation away from the bustling tourist areas. The beach\'s natural beauty and tranquil atmosphere make it an ideal spot for those seeking a peaceful retreat and a chance to connect with nature.\r\n', -8.64702, 115.114, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567144/baliholiday/destinations/szsry8bnqbhbz7e57kol.webp', '2024-12-21 05:28:34', '2024-12-21 05:28:34'),
(20, 'Uluwatu Temple (Pura Luhur Uluwatu)', 'Perched on a dramatic cliff overlooking the Indian Ocean, Uluwatu Temple is one of Bali\'s most iconic sea temples. Renowned for its stunning sunset views and traditional Kecak dance performances, the temple complex offers a mesmerizing cultural experience. The temple is also home to a large population of monkeys, adding to its charm and providing visitors with a unique blend of natural beauty and spiritual significance.\r\n', -8.82904, 115.085, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567147/baliholiday/destinations/ryq7sgwtsg0feclwnt9m.webp', '2024-12-21 05:37:14', '2024-12-21 05:37:14'),
(21, 'Besakih Temple', 'Known as the \"Mother Temple\" of Bali, Besakih Temple is the largest and most significant Hindu temple complex on the island. Located on the slopes of Mount Agung, Bali\'s highest mountain, Besakih consists of over 80 individual temples, each with its own unique architecture and significance. The temple complex is a major pilgrimage site and offers visitors an immersive experience into Balinese spirituality and traditional ceremonies.\r\n', -8.37377, 115.453, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567150/baliholiday/destinations/vlah0mnj7oga0vtthqtn.webp', '2024-12-21 05:39:30', '2024-12-21 05:39:30'),
(22, 'Ulun Danu Beratan Temple', 'Situated on the shores of Lake Beratan in the mountains, Ulun Danu Beratan Temple is a stunning water temple dedicated to Dewi Danu, the goddess of water. The temple\'s picturesque setting, with its reflection on the lake and surrounding mountains, makes it one of Bali\'s most scenic and tranquil temples. Visitors can explore the temple grounds, enjoy the serene environment, and learn about the temple\'s significance in Balinese irrigation and agriculture.\r\n', -8.27502, 115.167, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567152/baliholiday/destinations/homvdohai07slqnkky7m.webp', '2024-12-21 05:41:17', '2024-12-21 05:41:17'),
(23, 'Tirta Empul Temple ', 'Tirta Empul Temple is a sacred water temple renowned for its holy spring water, which is believed to have purifying properties. Located in the village of Manukaya, near Ubud, the temple attracts both pilgrims and tourists who participate in the traditional purification rituals. The temple complex features beautifully carved stone gateways and pools, offering a serene environment for spiritual reflection and cultural immersion.\r\n', -8.41552, 115.315, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567155/baliholiday/destinations/obywcls5nhxxaq1s4amx.webp', '2024-12-21 05:44:02', '2024-12-21 05:44:02'),
(24, 'Goa Gajah (Elephant Cave) ', 'Goa Gajah, or Elephant Cave, is an ancient archaeological site featuring a carved entrance resembling a menacing elephant. Located near Ubud, the temple complex dates back to the 11th century and is rich in Balinese Hindu and Buddhist influences. Visitors can explore the intricately carved caves, bathing pools, and lush gardens, gaining insight into Bali\'s historical and religious heritage.\r\n', -8.52322, 115.287, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567158/baliholiday/destinations/hsthx7chjcah34ijniyg.webp', '2024-12-21 05:48:02', '2024-12-21 05:48:02'),
(25, 'Pura Taman Ayun', 'Pura Taman Ayun is a majestic temple complex surrounded by a vast moat and beautifully landscaped gardens. Located in Mengwi, this temple is dedicated to the royal family of Mengwi and showcases traditional Balinese architecture with multiple shrines and pavilions. The serene environment and meticulously maintained gardens make Pura Taman Ayun a peaceful retreat for visitors seeking to experience Bali\'s spiritual and cultural traditions.\r\n', -8.5414, 115.173, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567162/baliholiday/destinations/fqjwjf80xk20y6nofnza.webp', '2024-12-21 05:50:01', '2024-12-21 05:50:01'),
(26, 'Tegenungan Waterfall', 'egenungan Waterfall is one of Bali\'s most accessible and popular waterfalls, located near Ubud. Surrounded by lush tropical vegetation, the waterfall cascades down from a height of approximately 15 meters into a serene pool, perfect for swimming and relaxation. The picturesque setting and easy accessibility make Tegenungan a favorite spot for both tourists and locals seeking to enjoy Bali\'s natural beauty.\r\n', -8.57533, 115.289, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567165/baliholiday/destinations/ifyuumh3n1wkxt5obxxm.webp', '2024-12-21 06:10:56', '2024-12-21 06:10:56'),
(27, 'AYANA Bali\'s Rock Bar', 'AYANA Bali\'s Rock Bar is a famous cliffside bar located within the AYANA Resort in Jimbaran, Bali. It is renowned for its stunning ocean views, perched high above the Indian Ocean on a rocky outcrop. The bar is accessible via a funicular ride and offers guests a unique experience with its chic, open-air design, cocktails, and live music. The sunset views here are particularly spectacular, making it a popular spot for both locals and tourists to enjoy drinks while watching the sun dip below the horizon.', -8.78613, 115.139, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567168/baliholiday/destinations/zncqpiio6fexttq5kydq.webp', '2024-12-21 06:23:48', '2024-12-21 06:23:48'),
(28, 'Tegalalang Rice Terrace', 'Tegallalang Rice Terrace is a picturesque set of lush, terraced rice fields located in Ubud, Bali. Known for its breathtaking views and traditional Balinese subak irrigation system, it’s a popular spot for tourists to explore on foot. The landscape offers stunning photo opportunities, especially during sunrise and sunset, making it a must-visit destination for nature lovers and photographers.', -8.43255, 115.279, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567171/baliholiday/destinations/ovz6t2wcod8kwniyvsdb.webp', '2024-12-21 06:30:14', '2024-12-21 06:30:14'),
(29, 'Atlas Beach Club', 'Atlas Beach Club is a popular beachfront venue, typically offering a mix of relaxed dining, entertainment, and vibrant nightlife. It\'s known for its beautiful seaside location, upscale amenities, and a lively atmosphere. Guests can enjoy a variety of experiences, from casual meals to high-energy events, often accompanied by live music, DJs, or themed parties. It\'s a great spot for both daytime relaxation and evening excitement.', -8.66519, 115.138, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567173/baliholiday/destinations/lpikqepwtlhvfjyuzh0u.webp', '2024-12-21 06:39:54', '2024-12-21 06:39:54'),
(30, 'FINNS Beach Club', 'Finns Beach Club is a renowned beachfront venue located in Bali, Indonesia. It\'s famous for its stunning beachfront setting, luxurious facilities, and vibrant atmosphere. The club features multiple infinity pools, restaurants, bars, and a relaxed yet chic vibe, offering both day-to-night experiences. Visitors can enjoy lounging by the pool, sipping cocktails, or dancing to live music and DJ performances. It\'s a popular destination for both tourists and locals looking for a combination of relaxation and fun by the ocean.', -8.66653, 115.139, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567175/baliholiday/destinations/cyqk7nxoxl8lleoezi9g.webp', '2024-12-21 06:48:17', '2024-12-21 06:48:17'),
(31, 'La Brisa Canggu', 'La Brisa is a laid-back, bohemian-style beach club located in Canggu, Bali. Known for its rustic, eclectic design with plenty of wooden accents and natural materials, La Brisa offers a relaxed atmosphere with stunning ocean views. The venue features a variety of pools, a beachside restaurant, and bars, making it perfect for a day of lounging, swimming, or enjoying cocktails and fresh food. La Brisa is popular for its sunset views, live music events, and its chilled-out vibe, attracting visitors seeking both relaxation and a touch of vibrant social energy.', -8.65401, 115.125, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567177/baliholiday/destinations/k2lluriozwh36v3pexue.webp', '2024-12-21 06:51:25', '2024-12-21 06:51:25'),
(32, 'Bali Zoo', 'Bali Zoo is a popular wildlife park located in Gianyar, Bali, offering visitors an immersive experience with a variety of animals. It features a wide range of exotic and native species, including tigers, elephants, orangutans, and reptiles. The zoo provides interactive experiences such as animal feedings, up-close encounters, and even the opportunity to take part in activities like elephant rides or breakfast with orangutans. With its lush, natural surroundings and focus on conservation, Bali Zoo offers both educational and fun experiences for families, animal lovers, and tourists looking to explore Bali\'s wildlife.', -8.59151, 115.266, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567178/baliholiday/destinations/fna8a5uemunnc6yxjj4a.webp', '2024-12-21 06:54:43', '2024-12-21 06:54:43'),
(33, 'Tlaga Singha Bali', 'Tlaga Singha Bali is a scenic and tranquil eco-tourism destination located in Ubud, Bali. Known for its beautiful natural surroundings, the venue features picturesque lakes, lush green landscapes, and a serene atmosphere. Visitors can enjoy activities like swimming, paddle boating, and cycling around the area. Tlaga Singha also has a café and restaurant where guests can relax and enjoy traditional Balinese cuisine with stunning views. The location is perfect for those seeking a peaceful escape in nature, offering both adventure and relaxation in a beautiful, sustainable environment.', -8.59154, 115.268, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567180/baliholiday/destinations/ncj2agojocoa6sjzj8gz.webp', '2024-12-21 06:57:45', '2024-12-21 06:57:45'),
(34, 'Ubud Palace', 'Ubud Palace (Puri Saren Agung) is a historic and cultural landmark located in the heart of Ubud, Bali. Once the royal residence of the Ubud monarchy, the palace showcases traditional Balinese architecture with ornate carvings, beautiful gardens, and grand pavilions. Visitors can explore the serene courtyards, admire intricate stonework, and observe the daily activities of the local community. Ubud Palace is also known for its cultural significance, often hosting traditional dance performances and art exhibitions in the evenings. It\'s a must-visit for those wanting to experience Bali\'s rich heritage and vibrant arts scene.', -8.50635, 115.263, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567182/baliholiday/destinations/xvhmlmihcaupufk6eiop.webp', '2024-12-21 07:00:15', '2024-12-21 07:00:15'),
(35, 'Taman Kemuda Saraswati Temple', 'Taman Kemuda Saraswati is a beautiful temple located in the heart of Ubud, Bali. Dedicated to Goddess Saraswati, the Hindu goddess of wisdom, knowledge, and the arts, this temple is known for its serene ambiance and stunning architectural features. The temple is surrounded by a tranquil lotus pond, adding to its peaceful atmosphere. Its intricate carvings and ornate stone structures showcase traditional Balinese temple design.\r\n\r\nPura Taman Kemuda Saraswati is not only a place of worship but also a cultural landmark, often hosting traditional dance performances, especially during the evening. It\'s a popular stop for visitors exploring Ubud, offering both spiritual insight and a visual treat, with the lotus pond reflecting the temple\'s beauty.', -8.50571, 115.261, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567184/baliholiday/destinations/v1nn7iqqivosbzjxn7sv.webp', '2024-12-21 07:02:23', '2024-12-21 07:02:23'),
(36, 'Bali Bird Park', 'Bali Bird Park is a popular wildlife park located in Gianyar, Bali, dedicated to the conservation and display of Indonesia\'s diverse bird species, as well as exotic birds from around the world. The park is home to over 1,000 birds from 250 species, including rare and endangered species like the Bali Starling, which is native to the island.\r\n\r\nVisitors can explore lush, beautifully landscaped aviaries that replicate the birds\' natural habitats. The park offers interactive experiences such as feeding sessions, bird shows, and the chance to get up close with some of the birds for photo opportunities. It’s a family-friendly attraction and a great way to learn about bird conservation while enjoying the vibrant colors and sounds of the avian residents.', -8.597, 115.252, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567186/baliholiday/destinations/fwzzdyn3hen5umkqkcwy.webp', '2024-12-21 07:05:02', '2024-12-21 07:05:02'),
(37, 'Bali Bird Park', 'Bali Bird Park is a popular wildlife park located in Gianyar, Bali, dedicated to the conservation and display of Indonesia\'s diverse bird species, as well as exotic birds from around the world. The park is home to over 1,000 birds from 250 species, including rare and endangered species like the Bali Starling, which is native to the island.\r\n\r\nVisitors can explore lush, beautifully landscaped aviaries that replicate the birds\' natural habitats. The park offers interactive experiences such as feeding sessions, bird shows, and the chance to get up close with some of the birds for photo opportunities. It’s a family-friendly attraction and a great way to learn about bird conservation while enjoying the vibrant colors and sounds of the avian residents.', -8.597, 115.252, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567187/baliholiday/destinations/yjf6hv1fpezzinphdgvu.webp', '2024-12-21 07:05:09', '2024-12-21 07:05:09'),
(38, 'Bali Butterfly Park (Taman Kupu-Kupu Bali)', 'Bali Butterfly Park (Taman Kupu-Kupu Bali) is a serene and educational attraction located in Wanasari, Tabanan, Bali. It’s dedicated to the conservation of butterflies and showcases a wide variety of species, both native to Bali and from other parts of Indonesia. The park is set in a lush, tropical garden with carefully designed enclosures that allow visitors to walk through vibrant butterfly-filled environments.\r\n\r\nIn addition to observing the butterflies in various stages of their life cycle (from eggs to larvae to chrysalises), guests can also learn about the importance of butterflies in the ecosystem. The park features informative displays, butterfly exhibits, and a souvenir shop with butterfly-themed products. It\'s a peaceful, family-friendly spot ideal for nature lovers and those interested in Bali’s rich biodiversity.', -8.4793, 115.135, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567189/baliholiday/destinations/jsfkxiyvaap3f4bydhds.webp', '2024-12-21 07:10:29', '2024-12-21 07:10:29'),
(39, 'Kemenuh Butterfly Park, Bali', 'Kemenuh Butterfly Park is another beautiful butterfly sanctuary located in the village of Kemenuh, Ubud, Bali. The park is a tranquil and educational space dedicated to the conservation and preservation of butterflies. It features an array of butterfly species, both local and from other parts of Indonesia, thriving in lush, tropical gardens designed to mimic their natural habitats.\r\n\r\nVisitors can walk through the park\'s scenic pathways and observe butterflies at various stages of their lifecycle, from larvae to pupae and adults. The park also has informative displays about the life cycle of butterflies, their role in the ecosystem, and the importance of conservation efforts. Kemenuh Butterfly Park is a peaceful, family-friendly attraction, offering a serene environment to appreciate nature, take photos, and learn about the fascinating world of butterflies.', -8.5692, 115.287, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567191/baliholiday/destinations/ebxoxkgusvs6oehpcjfe.webp', '2024-12-21 07:16:55', '2024-12-21 07:16:55'),
(40, 'I Gusti Ngurah Rai International Airport (DPS)', 'I Gusti Ngurah Rai International Airport (DPS) is the main international gateway to Bali, located in the southern part of the island, near the popular tourist areas of Kuta, Jimbaran, and Nusa Dua. Named after the Balinese hero I Gusti Ngurah Rai, the airport serves as the hub for both domestic and international flights, handling millions of visitors each year.', -8.74677, 115.168, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567192/baliholiday/destinations/uaxtnzbwlxvrfucerkqu.webp', '2024-12-21 07:20:55', '2024-12-21 07:20:55'),
(41, 'Tanjung Benoa Watersports', 'Tanjung Benoa Watersports is a popular destination in Bali, located in the Tanjung Benoa area, known for offering a wide variety of thrilling water activities. This beachfront spot is famous for its range of watersports, such as jet skiing, banana boat rides, parasailing, flyboarding, snorkeling, and glass-bottom boat tours. The calm, clear waters of Tanjung Benoa make it an ideal place for both beginners and experienced enthusiasts to try out different water-based adventures.', -8.75504, 115.219, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567194/baliholiday/destinations/s34bzrg9yyahnyeitinq.webp', '2024-12-21 07:28:42', '2024-12-21 07:28:42'),
(42, 'Gilimanuk Harbour ', 'Harbour Gilimanuk is a major port located on the western tip of Bali, in the village of Gilimanuk, Jembrana Regency. It serves as the primary gateway for ferry transport between Bali and the island of Java. The harbor is an important transport hub for both passengers and freight, connecting Bali to the Ketapang Port in Banyuwangi, East Java.', -8.16182, 114.437, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567196/baliholiday/destinations/m1q5t7klf0w1umlpke3a.webp', '2024-12-21 07:32:41', '2024-12-21 08:06:10'),
(43, 'Padang Bai Harbour ', 'Padang Bai Harbour is a small but important port located on the east coast of Bali, in the village of Padang Bai, Karangasem Regency. It serves as a key gateway for ferry travel between Bali and the nearby islands of Lombok and Gili Islands, making it a popular transit point for travelers heading to these destinations.', -8.53382, 115.51, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567198/baliholiday/destinations/ulhjicerxzbynsmikfij.webp', '2024-12-21 07:39:05', '2024-12-21 07:39:05'),
(44, 'Sanur Harbour ', 'Sanur Harbour (also known as Pantai Sanur or Sanur Port) is a popular port located in the Sanur area of southern Bali. It serves as a key departure point for boats and ferries traveling to neighboring islands, particularly Nusa Lembongan, Nusa Penida, and Nusa Ceningan, which are known for their stunning beaches, snorkeling, and diving spots.\r\n\r\nThe harbor offers regular boat services, both fast boats and traditional vessels, to these islands. It’s well-known for its relatively calm waters and easy access for passengers. The area around Sanur Harbour is also a popular tourist destination, with a relaxed beachfront atmosphere, resorts, restaurants, and shops.', -8.66899, 115.261, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567200/baliholiday/destinations/o9dolhxg6wndtfwkh0v0.webp', '2024-12-21 07:58:57', '2024-12-21 07:58:57'),
(45, 'Benoa Harbour', 'Port of Benoa (Pelabuhan Benoa) is a major commercial and passenger port located in the southern part of Bali, near the popular areas of Nusa Dua and Jimbaran. It plays a significant role in the island\'s shipping and cruise industry, handling both cargo and passenger ships.\r\n\r\nThe port is commonly used by cruise ships, with many international cruise lines making stops at Benoa for travelers to explore Bali. It serves as the main embarkation point for tourists arriving by sea, and its proximity to luxury resorts in Nusa Dua makes it a convenient gateway for visitors looking to access the island\'s southern regions.', -8.74271, 115.212, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567201/baliholiday/destinations/upzol8lbnelh7f0rnyhi.webp', '2024-12-21 08:05:49', '2024-12-21 08:05:49'),
(46, 'Jimbaran Beach', 'imbaran Beach is a stunning and serene stretch of coastline located in the southern part of Bali, known for its calm waters, golden sand, and vibrant seafood scene. It’s often considered one of the island’s most picturesque and peaceful beaches, offering a relaxing escape from the busier tourist areas.\r\n\r\nThe beach is particularly famous for its seafood dining, with dozens of beachfront restaurants offering freshly grilled fish, shrimp, lobster, and other seafood delicacies. These restaurants line the shore, and many serve meals with your toes in the sand, accompanied by spectacular sunset views over the Indian Ocean, making it a popular spot for romantic dinners and sunset picnics.', -8.77628, 115.166, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567203/baliholiday/destinations/lu5avb9jyyanw6votmab.webp', '2024-12-21 08:13:07', '2024-12-21 08:13:07'),
(47, 'Balangan Beach', 'Balangan Beach is a hidden gem located on the Bukit Peninsula in the southern part of Bali, near Jimbaran. Known for its stunning natural beauty, the beach features soft white sand, clear turquoise waters, and a backdrop of dramatic limestone cliffs. It’s a quieter, less crowded spot compared to some of Bali’s other popular beaches, making it a perfect destination for those seeking relaxation and natural scenery.', -8.7918, 115.123, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567205/baliholiday/destinations/jq1ek41xtuqaeezao1j2.webp', '2024-12-21 08:18:47', '2024-12-21 08:18:47'),
(48, 'Uluwatu Beach', 'Uluwatu Beach is one of Bali’s most iconic and beautiful beaches, located on the southern tip of the island in the Uluwatu area. It’s known for its dramatic cliffs, turquoise waters, and powerful surf breaks, making it a favorite destination for surfing enthusiasts and beach lovers alike.\r\n\r\nThe beach is somewhat hidden, nestled beneath steep cliffs, and can be accessed by a steep set of stairs that lead down to the sandy shore. The shoreline is relatively small, but the beauty and tranquility of Uluwatu Beach make it a must-visit for many travelers seeking a more secluded beach experience. ', -8.81385, 111.088, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567207/baliholiday/destinations/evahzkbjweskzhzkq62c.webp', '2024-12-21 08:22:44', '2024-12-21 08:22:44'),
(49, 'Sundays Beach Club', 'Sundays Beach Club is a stunning beach club located in the Uluwatu area of Bali, set on the beautiful Suluban Beach. This exclusive venue offers a laid-back, luxury experience, with a pristine stretch of white sand, crystal-clear turquoise waters, and dramatic cliffs surrounding the area. It’s perfect for those looking to relax in a more tranquil and sophisticated setting.\r\n\r\n', -8.84582, 115.149, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567208/baliholiday/destinations/uqdmkuck9xbnswvdliff.webp', '2024-12-21 08:28:23', '2024-12-21 08:28:23'),
(50, 'Melasti Beach', 'Melasti Beach is a beautiful and relatively quiet beach located on the southwestern coast of Bali, near the popular areas of Nusa Dua and Uluwatu. The beach is surrounded by impressive limestone cliffs, is also famous for its scenic access road, which winds down through high cliffs, offering breathtaking views as you descend towards the shore.', -8.84723, 115.163, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567210/baliholiday/destinations/c0qchcureo6cy53udpxw.webp', '2024-12-21 08:31:12', '2024-12-21 08:31:12'),
(51, 'Pandawa Beach', 'Pandawa Beach is a stunning and relatively hidden beach located on the southern coast of Bali, in the Kutuh Village, near the famous Uluwatu area. The beach is renowned for its soft white sand, clear turquoise waters, and dramatic cliffs. What makes Pandawa Beach particularly unique is the row of impressive limestone cliffs along the coastline, which have been carved to feature statues of the Pandawa brothers, from the Hindu epic Mahabharata.', -8.8452, 115.187, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567212/baliholiday/destinations/kddsw0oxcgpw5wxjpg13.webp', '2024-12-21 08:37:26', '2024-12-21 08:37:26'),
(52, 'Geger Beach', 'Geger Beach is a beautiful and relatively quiet beach located in the Nusa Dua area of southern Bali. Known for its clear, calm waters and soft white sand, it offers a more peaceful alternative to the busier beaches in Bali, making it an ideal destination for those seeking relaxation and natural beauty.', -8.81526, 115.226, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567214/baliholiday/destinations/xtlpiabjh497xrfd6xgj.webp', '2024-12-21 08:42:39', '2024-12-21 08:42:39'),
(53, 'Waterbom Bali', 'Waterbom Bali is one of the most popular and well-known water parks in Bali, located in Kuta. It\'s renowned for its wide range of exciting water slides, lush tropical landscaping, and family-friendly atmosphere, making it a must-visit attraction for both locals and tourists seeking a fun, action-packed day.', -8.72835, 115.169, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567215/baliholiday/destinations/obpmvuuoprynjqyrb2lc.webp', '2024-12-21 08:46:35', '2024-12-21 08:46:35'),
(54, 'Beachwalk Shopping Center', 'Beachwalk Shopping Center is a modern, open-air shopping mall located in Kuta, Bali, just a short walk from the famous Kuta Beach. Known for its contemporary design, spacious layout, and prime location, Beachwalk is one of the island\'s top shopping destinations for both tourists and locals.', -8.71675, 115.169, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567218/baliholiday/destinations/igslvh1iqnfpxt9623f3.webp', '2024-12-21 08:49:09', '2024-12-21 08:49:09'),
(55, 'The Keranjang Bali', 'The Keranjang is a stylish and vibrant retail store located in Seminyak, Bali, that offers a unique shopping experience focused on Indonesian and Balinese products. Known for its modern and artistic concept, The Keranjang showcases a curated selection of handcrafted goods, local souvenirs, and home decor made by local artisans.', -8.73157, 115.178, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567219/baliholiday/destinations/sijz6sd0m5ngzelffl4a.webp', '2024-12-21 08:50:58', '2024-12-21 08:50:58'),
(56, 'Krisna Oleh-Oleh', 'Krisna Oleh-Oleh is a popular chain of souvenir shops in Bali, known for offering a wide variety of affordable local products and souvenirs. With several locations around the island, Krisna has become a go-to destination for both tourists and locals looking to purchase traditional Balinese goods, snacks, and keepsakes.', -8.72967, 115.179, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567221/baliholiday/destinations/qgeahezzvlfoitkmyio5.webp', '2024-12-21 08:53:13', '2024-12-21 08:53:13'),
(57, 'Finns Recreation Club Canggu', 'Finns Recreation Club is a premier lifestyle and entertainment destination located in Canggu, Bali. The club offers a wide range of activities and facilities catering to both tourists and locals, making it a popular spot for families, groups, and individuals looking for fun, relaxation, and fitness.', -8.66228, 111.148, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567222/baliholiday/destinations/skyvhzj52nvxzvwiu63r.webp', '2024-12-21 08:55:00', '2024-12-21 08:55:00'),
(58, 'Canggu Love Anchor Store', 'Canggu Love Anchor Store is a trendy lifestyle boutique located in Canggu, Bali, offering a curated selection of stylish and unique products. It’s well-known for its laid-back, bohemian vibe and is a favorite among both locals and tourists. The store offers a variety of items that reflect the cool, beachy lifestyle of Canggu, with a focus on fashion, home decor, and accessories.', -8.6516, 115.134, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567224/baliholiday/destinations/p1kadmf5hygsm9gjksqb.webp', '2024-12-21 08:56:57', '2024-12-21 08:56:57'),
(59, 'Double Six Beach', 'Double Six Beach (Pantai Double Six) is a vibrant and popular beach located in Seminyak, Bali, known for its lively atmosphere, beautiful sunsets, and excellent beachfront dining options. It\'s a great destination for both relaxation and entertainment, attracting visitors looking to enjoy Bali\'s coastal beauty alongside trendy beach clubs, restaurants, and water activities.', -8.69445, 115.161, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567226/baliholiday/destinations/fe1rmoehkwnnowonqdtx.webp', '2024-12-21 08:59:58', '2024-12-21 08:59:58'),
(60, 'Potato Head Beach Club', 'Potato Head Beach Club is one of Bali\'s most iconic and luxurious beachfront venues, located in Seminyak. Known for its stylish design, stunning ocean views, and vibrant atmosphere, Potato Head is a must-visit destination for those looking to experience Bali’s high-end beach club scene.', -8.67604, 115.15, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567228/baliholiday/destinations/toulzgredlrsr6vai3e4.webp', '2024-12-21 09:01:51', '2024-12-21 09:01:51'),
(61, 'Cafe del Mar Bali', 'Cafe del Mar Bali is a trendy and upscale beach club located in Canggu, Bali, offering a mix of luxury, relaxation, and vibrant beachside ambiance. As part of the Cafe del Mar brand, which originated in Ibiza, this venue brings a similar Mediterranean-inspired vibe to Bali, blending stunning beachfront views with stylish design, great food, and top-notch entertainment.', -8.67056, 115.145, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567229/baliholiday/destinations/ygudhkfxuuzt0hdtjegz.webp', '2024-12-21 09:04:26', '2024-12-21 09:04:26'),
(62, 'La Favela ', 'La Favela is one of Bali’s most iconic and eclectic venues, located in Seminyak. It’s a vibrant restaurant, bar, and nightclub that blends a mix of tropical garden vibes with vintage-inspired decor, creating a unique, bohemian, and laid-back atmosphere. Known for its eclectic, whimsical interiors, La Favela offers a one-of-a-kind experience that combines dining, music, and nightlife in a single venue.', -10.6836, 115.163, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567231/baliholiday/destinations/veoqa5arcroib9tlgzet.webp', '2024-12-21 09:09:20', '2024-12-21 09:09:20'),
(63, 'Garuda Wisnu Kencana Cultural Park (GWK)', 'Garuda Wisnu Kencana Cultural Park (often abbreviated as GWK Cultural Park) is one of Bali\'s most iconic cultural attractions, located in Ungasan, southern Bali. The park is a stunning cultural and artistic hub, famous for its massive Garuda Wisnu Kencana statue, one of the largest statues in the world, and its unique blend of art, culture, and natural beauty.', -8.8102, 115.168, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567233/baliholiday/destinations/gwcno6es4urpv5a6plue.webp', '2024-12-21 09:12:01', '2024-12-26 10:23:30'),
(64, 'Mason Elephant Park', 'Mason Elephant Park located in Taro Village, Ubud, Bali, is one of the island\'s premier wildlife attractions. The park offers an unforgettable opportunity to get up close and personal with Sumatran elephants, combining fun, education, and conservation efforts in a lush, natural environment.', -8.39121, 115.284, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567235/baliholiday/destinations/zktfgd6nmraujxwrlz5q.webp', '2024-12-21 09:20:31', '2024-12-21 09:20:31'),
(65, 'Museum Seni Agung Rai (ARMA Museum) ', 'Museum Seni Agung Rai (often referred to as ARMA Museum) is a renowned cultural institution located in Ubud, Bali, that showcases the rich history and vibrant art scene of Bali and Indonesia. The museum was founded by Agung Rai, a prominent art collector and philanthropist, with the aim of preserving and promoting Balinese and Indonesian art, as well as providing a space for cultural education and exchange.', -8.5226, 115.264, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567236/baliholiday/destinations/osd6nwa54k2w7sb35ouc.webp', '2024-12-21 09:26:43', '2024-12-21 09:26:43'),
(66, 'Ubud Art Market', 'Ubud Art Market (or Pasar Seni Ubud) is one of Bali’s most famous markets, located in the heart of Ubud, Bali\'s cultural and artistic hub. The market is a must-visit for anyone wanting to experience the vibrant arts and crafts scene of the island, offering a wide array of traditional and contemporary Balinese handicrafts, textiles, artwork, and souvenirs. It’s an ideal spot for those looking to immerse themselves in Bali’s rich culture and bring home unique, handcrafted items.', -8.50697, 115.263, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567238/baliholiday/destinations/zbzrcr0e8lnykacnsg5j.webp', '2024-12-21 09:34:11', '2024-12-21 09:34:11'),
(67, 'Aling-Aling Waterfall', 'Aling-Aling Waterfall is a hidden gem for nature lovers, adventure enthusiasts, and those seeking an off-the-beaten-path experience in Bali. The combination of lush scenery, multiple waterfalls, and adventure activities like natural waterslides and cliff jumping makes it an exciting yet peaceful escape into Bali’s wild beauty.The trek to Aling-Aling Waterfall is a moderate-level hike the journey to the waterfall is relatively short but involves some challenging terrain, making it suitable for those who are reasonably fit and enjoy a bit of adventure.', -11.1747, 115.104, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567241/baliholiday/destinations/sut9rryicpyhk9jy8rq6.webp', '2024-12-21 09:43:03', '2024-12-21 09:43:03'),
(68, 'Tamblingan Lake', 'Danau Tamblingan is located near the town of Singaraja, in the northern part of Bali. It’s about a 2-3 hour drive from Ubud or Denpasar, The lake is sacred in Balinese Hinduism, with the Pura Ulun Danu Tamblingan temple located on its shores. Visitors can enjoy trekking, canoeing, and the stunning natural beauty of the area, making it a perfect destination for nature lovers seeking tranquility.', -8.26448, 115.092, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567242/baliholiday/destinations/fvahqccbkzuxipstwbx1.webp', '2024-12-21 09:49:36', '2024-12-21 09:49:36'),
(69, 'Menjangan Island', 'Menjangan Island is a small, uninhabited island located off the northwestern coast of Bali, part of the West Bali National Park. Known for its pristine beaches, clear turquoise waters, and vibrant marine life, it is a popular destination for snorkeling, scuba diving, and nature lovers seeking a tranquil escape.', -8.09805, 114.515, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567244/baliholiday/destinations/yc36zogtauwnzmq85ds2.webp', '2024-12-21 09:58:48', '2024-12-21 09:58:48'),
(70, 'Lempuyang Temple', 'Lempuyang refers to Pura Lempuyang, one of Bali\'s most iconic and sacred temples, located in the Karangasem regency on the east coast of Bali, near Mount Agung. It\'s often called the \"Gates of Heaven\" due to the stunning view of Mount Agung framed by the temple\'s entrance gates, making it a popular spot for visitors seeking both spiritual experiences and photographic opportunities.', -8.39175, 115.631, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567246/baliholiday/destinations/prfb2kh5y1onglu9behv.webp', '2024-12-21 10:03:14', '2024-12-21 10:03:14'),
(71, 'Tirta Gangga Water Palace', 'Tirta Gangga is a stunning water palace located in the Karangasem regency in eastern Bali, near the town of Amlapura. Built in the early 20th century by the King of Karangasem, Tirta Gangga is renowned for its beautifully landscaped gardens, swimming pools, and elaborate water features. The name \"Tirta Gangga\" means \"holy water from the Ganges\", referencing the spiritual significance of water in Hinduism.', -8.41214, 115.587, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567247/baliholiday/destinations/csfrhy4dhrkry2vfhdv8.webp', '2024-12-21 10:05:54', '2024-12-21 10:05:54'),
(72, 'Kintamani', 'Kintamani offers some of the most dramatic views in Bali, with Lake Batur, Mount Batur, and the surrounding caldera creating a breathtaking landscape. The volcanic lake is surrounded by lush green fields, and the towering Mount Batur provides a striking backdrop.', -8.25245, 115.332, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567249/baliholiday/destinations/v0wtjdcuucy7nhhpznyj.webp', '2024-12-21 10:13:22', '2024-12-21 10:13:22'),
(73, 'The Bali Handara Golf Gate', 'The Bali Handara Golf Gate is a famous and iconic landmark located at the entrance of the Bali Handara Golf & Resort, situated in the Bedugul area of Bali, near Lake Bratan. Known for its striking traditional Balinese gate (Candi Bentar), the Bali Handara Golf Gate has become a popular photographic spot for visitors and a symbol of the island’s rich culture and natural beauty.', -8.25274, 115.158, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567251/baliholiday/destinations/qxz5v8ugb3efpvxsblvb.webp', '2024-12-21 10:17:10', '2024-12-21 10:17:10'),
(74, 'Alas Kedaton Monkey', 'Alas Kedaton is a small, serene forest sanctuary located in the Tabanan Regency of Bali. It is a monkey forest that is home to a large population of long-tailed macaques. The name \"Alas Kedaton\" translates to \"sacred forest,\" and also features a sacred temple within the forest grounds. Alas Kedaton is located near other significant cultural and natural attractions in Bali, such as the Tanah Lot Temple, a famous sea temple, and the Taman Ayun Temple, known for its beautiful gardens and historical significance.', -8.52923, 115.155, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567252/baliholiday/destinations/anpgqb49ubuazizcxg1x.webp', '2024-12-21 10:24:30', '2024-12-21 10:24:30'),
(75, 'Penglipuran Village', 'Desa Penglipuran is a traditional Balinese village located in the Bangli Regency, in the central part of Bali, Indonesia. Known for its well-preserved cultural heritage, beautiful surroundings, and unique village layout, Desa Penglipuran offers visitors a glimpse into authentic Balinese life.', -8.42244, 115.36, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567254/baliholiday/destinations/gdgdjrhq9dx6i6fvonws.webp', '2024-12-21 10:27:02', '2024-12-21 10:27:02'),
(76, 'Tenganan Village', 'Tenganan Village is one of Bali\'s most unique and culturally rich villages, located in the Karangasem Regency, on the eastern side of Bali, Indonesia. It is renowned for its deep connection to Bali’s ancient traditions, and it is one of the few remaining Bali Aga villages—meaning it is home to the indigenous Balinese people who have preserved their distinct customs and way of life. Tenganan is a fascinating destination for those interested in experiencing authentic Balinese culture in a rural, peaceful setting.\r\n\r\n', -8.47652, 115.566, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567256/baliholiday/destinations/y5osk8gpdcvbkttwimiz.webp', '2024-12-21 10:30:05', '2024-12-21 10:30:05'),
(77, 'Jatiluwih Rice Terraces', 'Jatiluwih Rice Terraces is one of Bali\'s most iconic and breathtaking landscapes, located in the Tabanan Regency in the central part of the island. The terraces are renowned for their stunning beauty, vast green fields, and intricate irrigation system, known as Subak, which has earned the area recognition as a UNESCO World Heritage site. Jatiluwih offers visitors not only a picturesque escape but also a deep insight into Bali\'s traditional agricultural practices.\r\n\r\n', -8.37004, 115.131, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567257/baliholiday/destinations/s9ycczhxwyxxum4hksj8.webp', '2024-12-21 10:32:40', '2024-12-21 10:32:40'),
(78, 'Monumen Bajra Sandhi', 'Monumen Bajra Sandhi is a striking and historically significant monument located in Denpasar, the capital of Bali, Indonesia. The monument is dedicated to the struggles of the Balinese people in their fight for independence and freedom, particularly during the periods of Dutch colonial rule and the Bali War of Independence (1945–1949). It serves as a tribute to the spirit of resistance, the cultural heritage, and the historical significance of Bali.\r\n\r\n', -8.67151, 115.234, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567259/baliholiday/destinations/xuuwrrl2dkpi3idqm9lm.webp', '2024-12-21 10:41:09', '2024-12-21 10:41:09');
INSERT INTO `destinations` (`id`, `name`, `description`, `lat`, `lng`, `image`, `createdAt`, `updatedAt`) VALUES
(79, 'Serangan Island', 'Serangan Island is a small island located to the southeast of Denpasar, the capital city of Bali, Indonesia. It is well-known for its role as a sea turtle sanctuary, its historical significance, and its natural beauty. It also attracts visitors for its cultural heritage and peaceful environment, making it a unique destination in Bali.', -8.72404, 115.238, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567261/baliholiday/destinations/orvxr4nx2lj43dl31bvw.webp', '2024-12-24 05:31:12', '2024-12-24 05:31:12'),
(80, 'Museum Pasifika', 'Museum Pasifika is a unique and culturally significant museum located in Nusa Dua, Bali, Indonesia. It is dedicated to showcasing the rich and diverse artistic heritage of the Asia-Pacific region. The museum is renowned for its extensive collection of artworks, particularly those that reflect the cultural exchanges between the Pacific Islands, Southeast Asia, and the rest of the world. , ', -8.79968, 115.231, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567262/baliholiday/destinations/mqenyx6pe9doexlugog6.webp', '2024-12-24 05:34:05', '2024-12-24 05:34:05'),
(81, 'Saka Museum', 'Saka Museum in Bali is a cultural institution that is dedicated to showcasing the traditional art, crafts, and heritage of Bali, particularly the Saka art style and other forms of Balinese cultural expressions. The museum serves as both a place of preservation and education, allowing visitors to experience and learn about Bali\'s rich history and artistic traditions.', -8.78935, 115.143, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567264/baliholiday/destinations/vpofzxiuahzrgzgjybmz.webp', '2024-12-24 05:38:37', '2024-12-24 05:38:37'),
(82, 'Museum Puri Lukisan ', 'Museum Puri Lukisan is one of Bali\'s most important art museums, located in the cultural heart of the island, Ubud. The museum is dedicated to preserving and showcasing Balinese and Indonesian art, with a particular focus on the traditional and modern paintings that have shaped Bali’s artistic landscape. Established in 1956, Museum Puri Lukisan is widely regarded as a key institution in Bali’s art scene. ', -8.50507, 115.26, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567266/baliholiday/destinations/xxri8tqohjh9ybbilhfb.webp', '2024-12-24 05:51:35', '2024-12-24 05:51:35'),
(83, 'Museum Arkeologi Bali', 'Museum Arkeologi Bali (Bali Archaeological Museum) is a museum dedicated to preserving and showcasing the rich archaeological history of Bali and its surrounding regions. Located in Denpasar, the capital city of Bali, this museum offers visitors a chance to explore Bali\'s ancient past, from its early human settlement to the evolution of its distinctive culture and art. ', 8.51938, 111.293, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567268/baliholiday/destinations/xtqyjjzleg4vvmsf67ae.webp', '2024-12-24 05:53:57', '2024-12-24 05:53:57'),
(84, 'The Blanco Renaissance Museum', 'The Blanco Renaissance Museum is one of Bali\'s most unique and iconic museums, dedicated to the life and works of Antonio Blanco, a highly renowned Spanish-American artist who made Bali his home. Located in Ubud, the cultural heart of Bali, the museum offers a fascinating insight into the life and art of an artist who became deeply inspired by the island\'s natural beauty, culture, and people.', -8.50472, 115.254, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567269/baliholiday/destinations/tvpmf2ihpku2flstjcpy.webp', '2024-12-24 05:57:34', '2024-12-24 05:57:34'),
(85, 'Neka Art Museum', 'Neka Art Museum is one of Bali’s premier art museums, located in Ubud, the cultural heart of the island. Established in 1982 by Suteja Neka, the museum aims to preserve, showcase, and promote the art of Bali and Indonesia, particularly modern and contemporary works that reflect both traditional Balinese art and the influence of Western styles.', -8.49223, 115.254, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567271/baliholiday/destinations/itv1eqa4hthewqqsu8kg.webp', '2024-12-24 06:02:29', '2024-12-24 06:02:29'),
(86, 'Setia Darma House of Mask and Puppets', 'Setia Darma House of Masks and Puppets is one of Bali\'s hidden gems, offering visitors a fascinating and immersive experience into the world of masks and puppetry from Indonesia and beyond. Located in Mas Village, Ubud, this museum is dedicated to preserving and showcasing the rich tradition of mask-making and puppetry, which are integral to many cultures across Indonesia, especially in Bali, as well as in other parts of the world. ', -8.5338, 115.28, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567273/baliholiday/destinations/tfq1wzgwrcb4ukenmorh.webp', '2024-12-24 06:06:07', '2024-12-24 06:06:07'),
(87, 'Goa Lawah Temple', 'Goa Lawah Temple, also known as the Bat Cave Temple, is one of the most important Hindu temples in Bali, Indonesia. Situated on the island\'s eastern coast near the village of Dawan, in the Klungkung regency, this temple is dedicated to Lord Shiva and is a significant place of worship for Balinese Hindus., ', -8.54896, 115.469, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567274/baliholiday/destinations/yuryiw3cijnidnbxqqtg.webp', '2024-12-24 07:12:24', '2024-12-24 07:12:24'),
(88, 'Mengening Temple ', 'Pura Mengening Temple is a hidden spiritual sanctuary that offers visitors a chance to experience Bali\'s rich cultural and religious heritage in a peaceful, serene setting. Its combination of natural beauty, sacred water springs, and tranquil atmosphere makes it an ideal destination for those looking to immerse themselves in Bali\'s spiritual traditions. Whether you are seeking purification, peace, or simply a quiet escape, this temple provides a meaningful experience. ', -8.41815, 115.312, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567276/baliholiday/destinations/dzdmgo8vou8sgxx6j8sw.webp', '2024-12-24 07:19:39', '2024-12-24 07:19:39'),
(89, 'Genah Melukad Sebatu', 'Genah Melukad Sebatu is a small, tranquil village located in the Tampaksiring district, Gianyar Regency, Bali. This area is known for its spiritual atmosphere, which is closely tied to the island\'s Hindu culture, with many temples and natural springs in the vicinity, which are traditionally used in purification ceremonies (melukat)', -8.39711, 115.298, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567278/baliholiday/destinations/n6havhf41rw5vi5mtifw.webp', '2024-12-24 07:26:23', '2024-12-24 07:26:23'),
(90, 'Taman Beji Griya Waterfall', 'Taman Beji Griya is a sacred site dedicated to water purification, with natural holy springs at the heart of the temple. The word \"Beji\" refers to a holy spring used for ritual cleansing, which is central to the temple\'s significance.  You can partake in a traditional purification ceremony by bathing in the holy spring water, which is said to cleanse both the body and spirit.', -8.50115, 115.219, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567279/baliholiday/destinations/x2bkgnginjym5z2xhgiz.webp', '2024-12-24 07:33:20', '2024-12-24 07:33:20'),
(91, 'Bali Safari & Marine Park', 'Bali Safari & Marine Park is one of Bali\'s top family-friendly attractions, located in Gianyar Regency, on the island’s southeastern coast. It is an exciting and educational destination where visitors can experience a wide variety of animals from around the world, as well as enjoy exciting shows, animal encounters, and water activities.', -8.58408, 115.348, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567281/baliholiday/destinations/fwummwqb702288ihaj4u.webp', '2024-12-24 07:36:26', '2024-12-24 07:36:26'),
(92, 'Tibumana Waterfall', 'Tibumana Waterfall is a stunning and relatively hidden waterfall located in the central part of Bali, Indonesia. It\'s situated near the village of Apuan, in the Bangli Regency, which is about a 30-minute drive from Ubud, Bali\'s cultural heart. The waterfall is a bit off the beaten path compared to more popular waterfalls in Bali like Tegenungan or Gitgit, but it has gained recognition for its serene beauty and tranquil surroundings. ', -8.50648, 115.333, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567283/baliholiday/destinations/uhqdaplurfqkgg5o6f7x.webp', '2024-12-24 08:26:43', '2024-12-24 08:26:43'),
(93, 'Tukad Cepung Waterfall', 'Tukad Cepung Waterfall is one of Bali\'s most unique and visually stunning waterfalls, located in the Bangli Regency, near the village of Tembuku. This waterfall stands out for its extraordinary setting, as it cascades down from a cave-like opening within the jungle, creating an almost magical scene where sunlight filters through the rocks, casting beautiful beams of light into the waterfall\'s mist. ', -8.44093, 115.387, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567284/baliholiday/destinations/khpbnvdqhquaaatzldmu.webp', '2024-12-24 08:30:21', '2024-12-24 08:30:21'),
(94, 'Banyumala Twin Waterfalls', 'Banyumala Twin Waterfalls is one of Bali’s lesser-known but equally stunning natural attractions. Located in the northern part of the island, near the village of Wanagiri in the Buleleng Regency, Banyumala Twin Waterfalls offers a peaceful, off-the-beaten-path experience. The waterfall consists of two beautiful streams cascading down from the mountains, creating a serene and picturesque setting in the jungle.', -8.21696, 115.102, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567286/baliholiday/destinations/nrsdqc1lwkrzr9st5eoo.webp', '2024-12-24 08:34:12', '2024-12-24 08:34:12'),
(95, 'Air Terjun Munduk Waterfall', 'Air Terjun Munduk is one of the stunning waterfalls located in the village of Munduk, in the Buleleng Regency of northern Bali. Known for its peaceful surroundings and pristine natural beauty, Munduk Waterfall is a popular destination for nature lovers and those seeking a quieter, more serene experience compared to Bali\'s more well-known waterfalls.', -8.25369, 115.079, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567288/baliholiday/destinations/pnnyycufq99kymy3u4ma.webp', '2024-12-24 08:36:44', '2024-12-24 08:36:44'),
(96, 'Gitgit Waterfall ', 'Gitgit Waterfall is a single waterfall with a height of about 35 meters (115 feet). The waterfall cascades down in a series of tiers, creating a powerful and captivating scene. The flow of water is strong, particularly during the rainy season, and it creates a cool mist that enhances the waterfall’s dramatic atmosphere. ', -8.18791, 115.137, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567289/baliholiday/destinations/tth14f0uatmysbdgkiit.webp', '2024-12-24 08:41:05', '2024-12-24 08:41:05'),
(97, 'Banyu Wana Amertha Waterfall', 'Banyu Wana Amertha Waterfall is one of Bali’s hidden gems, located in the Sukasada District of the Buleleng Regency in northern Bali. This waterfall is a bit off the beaten path compared to more famous waterfalls like Gitgit or Tegenungan, which makes it an excellent destination for those seeking a peaceful and less crowded natural experience. The name \"Banyu Wana Amertha\" roughly translates to \"The Water of Eternal Life,\" a fitting description for its serene beauty and tranquil atmosphere.', -8.21258, 115.122, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567291/baliholiday/destinations/xgzwojmbija9dm6fgokg.webp', '2024-12-24 08:48:42', '2024-12-24 08:48:42'),
(98, 'Suwat Waterfall', 'Suwat Waterfall is a beautiful and relatively hidden waterfall located in Bali\'s Gianyar Regency, in the eastern part of the island. Known for its tranquil atmosphere and the dramatic setting surrounded by lush tropical jungle, Suwat Waterfall is a great destination for nature lovers and those seeking a more off-the-beaten-path experience in Bali.', -8.48745, 115.318, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567293/baliholiday/destinations/gtabjqurwferwbeswajx.webp', '2024-12-24 08:53:52', '2024-12-24 08:53:52'),
(99, 'Banjar Hot Spring', 'Banjar Hot Springs (known locally as Air Panas Banjar) is a popular natural hot spring located in the Banjar Village, in the Buleleng Regency of northern Bali. Situated about 10 kilometers from Lovina Beach, it’s an idyllic place to relax and unwind while enjoying the healing properties of the natural thermal waters. Known for its peaceful atmosphere and scenic surroundings, Banjar Hot Springs has become a must-visit spot for those looking to experience a more tranquil and rejuvenating side of Bali. ', -8.20097, 114.966, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567294/baliholiday/destinations/wbfl4v1h6hm4ldv5o3ae.webp', '2024-12-24 09:00:13', '2024-12-24 09:00:13'),
(100, 'Toya Devasya Hot Spring', 'Toya Devasya is a luxurious hot spring resort located on the slopes of Mount Batur in Kintamani, northern Bali. Known for its stunning natural beauty and breathtaking views of Lake Batur and the surrounding mountains, Toya Devasya offers a perfect combination of relaxation, wellness, and adventure. It’s one of the most popular hot spring destinations in Bali, providing visitors with an opportunity to soak in mineral-rich, therapeutic waters while surrounded by Bali’s serene natural landscape.', -8.25016, 115.401, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567296/baliholiday/destinations/oj83rnsyvkexv1ftxoyp.webp', '2024-12-24 09:02:59', '2024-12-24 09:02:59'),
(101, 'Batuan Temple', 'Batuan Temple is a stunning Balinese Hindu temple located in the Gianyar Regency, known for its intricate stone carvings and traditional architecture. Built in the 10th century, it serves as a place of worship and a cultural landmark, showcasing Bali’s rich heritage. The temple\'s serene atmosphere and beautifully maintained gardens make it a must-visit spot for those seeking to experience authentic Balinese spirituality. Visitors can admire its unique sculptures and participate in cultural ceremonies held throughout the year.\r\n\r\n', -8.58212, 115.276, 'https://res.cloudinary.com/djibcjquk/image/upload/v1773567299/baliholiday/destinations/l4gkqowexhz32ib85mnj.webp', '2024-12-26 10:50:30', '2024-12-26 10:50:30');

