INSERT INTO `tour_plan` (`id`, `title1`, `coordinatesleft1`, `coordinatesright1`, `description1`, `link1`, `title2`, `coordinatesleft2`, `coordinatesright2`, `description2`, `link2`, `title3`, `coordinatesleft3`, `coordinatesright3`, `description3`, `link3`, `title4`, `coordinatesleft4`, `coordinatesright4`, `description4`, `link4`, `title5`, `coordinatesleft5`, `coordinatesright5`, `description5`, `link5`, `title6`, `coordinatesleft6`, `coordinatesright6`, `description6`, `link6`, `title7`, `coordinatesleft7`, `coordinatesright7`, `description7`, `link7`, `title8`, `coordinatesleft8`, `coordinatesright8`, `description8`, `link8`, `title9`, `coordinatesleft9`, `coordinatesright9`, `description9`, `link9`, `createdAt`, `updatedAt`, `tourId`) VALUES
(1, 'Coffee Plantation and Swing', '-8.404569670044884', ' 115.32228702651527', 'Start your day with an enriching visit to a local coffee plantation, where you can learn about the intricate process of Balinese coffee production. Sample a variety of unique blends and indulge in a thrilling ride on the famous jungle swing, capturing unforgettable moments amidst the verdant surroundings.', 'https://baliholiday.xyz/blog/a-journey-through-taste-and-tradition-exploring-bali-coffee-plantations', 'Ubud Monkey Forest', '-8.519171882419906', '115.26060130888064', 'Continue your adventure with a visit to the renowned Ubud Monkey Forest, home to a lively community of long-tailed macaques. Observe these playful primates in their natural habitat and immerse yourself in the tranquil ambiance of this lush jungle sanctuary.', 'https://www.baliholiday.xyz/blog/exploring-the-natural-beauty-and-sacred-monkeys-in-sacred-monkey-forest,-ubud', 'Ubud Palace and Art Market', '-8.506044044004156', '115.26259511910803', 'Embark on a cultural exploration of central Ubud, beginning with a tour of the historic Ubud Palace (Puri Saren Ubud), once the royal residence of Balinese royalty. Then, wander through the vibrant lanes of the Ubud Art Market, where you\'ll find an array of traditional handicrafts, souvenirs, and artistic treasures.', 'https://www.baliholiday.xyz/blog/a-royal-juxtaposition-ubud-palace-and-the-ubud-art-market', 'Tirta Empul Temple', '-8.414368786518763', '115.31510753921592', 'Delve deeper into Bali\'s rich spiritual heritage with a visit to Tirta Empul Temple, renowned for its sacred water purification rituals. Witness locals partake in traditional cleansing ceremonies and gain insights into the profound significance of this ancient Hindu temple.', 'https://baliholiday.xyz/blog/a-journey-of-purification-exploring-tirta-empul,-bali\'s-water-temple', 'Hidden Waterfall', '-8.57513928260305', '115.28893841127984', 'Conclude your day with a scenic journey to Tegunungan Waterfall, a hidden oasis nestled amidst lush greenery. Take a leisurely stroll to reach the base of the falls, where you can cool off with a refreshing swim in the crystal-clear waters, surrounded by the breathtaking beauty of Bali\'s natural landscape.', 'https://www.baliholiday.xyz/blog/tegenungan-waterfall-a-refreshing-oasis-in-the-heart-of-ubud\'s-natural-splendor', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2024-04-01 17:58:04', '2024-04-10 12:40:28', 2),
(2, 'Garuda Wisnu Kencana', '-8.81021074634558', '115.16757713772124', 'Begin your day by exploring the cultural park of Garuda Wisnu Kencana. Here, you’ll find the largest statue in Bali—an impressive depiction of Garuda Wisnu. Take your time to stroll through the vast park and appreciate the artistry.', '', 'Pandawa Beach', '-8.844596039688021', '115.18716921168725', 'Afterward, head to Pandawa Beach, known for its pristine white sand and statues portraying the Panca Pandawa characters. Capture some memorable photos against the backdrop of the sparkling ocean.', '', 'Uluwatu Temple', '-8.829070401854366', '115.08489314910105', ' As the day progresses, visit the iconic Uluwatu Temple, dramatically perched on a cliff overlooking the Indian Ocean. The temple offers breathtaking sunset views, making it an ideal spot for reflection and awe.', 'https://www.baliholiday.xyz/blog/uluwatu-temple-bali-clifftop-gem-where-spirituality-meets-breathtaking-vistas', 'Kecak and Fire Dance Performance', '-8.829070401854366', '115.08489314910105', 'Conclude your Uluwatu adventure with the mesmerizing Kecak dance. As the sun sets, witness this traditional Balinese performance that weaves stories from the epic Ramayana. The rhythmic chanting and fiery spectacle will leave you spellbound.', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2024-04-05 06:39:36', '2024-04-09 15:14:26', 3),
(3, 'Taman Ayun Temple', '-8.541280346491893', '115.17266653658395', 'Embark on a captivating journey as you begin your day with a visit to the majestic Taman Ayun Temple. This esteemed UNESCO World Heritage site, steeped in rich history dating back to the 16th century, is a testament to the splendor of Balinese Hindu architecture.\nIndulge your senses as you meander through the tranquil temple grounds, enveloped by the serene ambiance of a vast fish pond. Immerse yourself in the intricate craftsmanship adorning the temple, allowing yourself to be transported to a realm of profound tranquility.', 'https://www.baliholiday.xyz/blog/-taman-ayun-temple-a-majestic-oasis-in-the-heart-of-bali', 'Alas Kedaton', '-8.529185406588052', '115.15536175305981', 'Continue your exploration with a visit to the sacred enclave of Alas Kedaton, a sanctuary harmoniously nestled amidst lush greenery. Here, amidst ancient stone structures, encounter the mischievous inhabitants of the forest – playful macaques.\nFeel the mystical aura permeate the air as you wander amidst towering trees, observing the monkeys in their natural habitat, offering glimpses into their daily lives and behaviors.', 'https://www.baliholiday.xyz/blog/alas-kedaton-monkeying-around-in-a-balinese-sanctuary', 'Tanah Lot Temple', '-8.61655038307422', '115.08685618004664', 'As the day unfolds, prepare to be captivated by the allure of Tanah Lot Temple, an iconic marvel perched dramatically atop a rocky outcrop amidst the sea. Marvel at the breathtaking vistas of the sun setting against the backdrop of this Hindu sanctuary, casting an ethereal glow over the landscape.', 'https://www.baliholiday.xyz/blog/tanah-lot-bali-iconic-sea-temple,-where-beauty-meets-serenity', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2024-04-05 07:15:22', '2024-04-09 14:54:37', 4),
(4, 'Ulun Danu Temple', '-8.274203007415753', '115.16685243055402', 'Begin your day by immersing yourself in the cultural embrace of Ulun Danu Temple. This UNESCO World Heritage site, nestled on the shores of Lake Beratan in Bedugul, is a testament to exquisite Balinese Hindu architecture.', 'https://www.baliholiday.xyz/blog/ulun-danu-beratan-a-majestic-temple-on-bali\'s-serene-lake', 'Handara Gate', '-8.252816795398559', '115.15826243771228', 'Next, venture to the iconic Handara Gate. This Balinese-styled structure resembles an entrance to a temple, symbolizing the passage from the outer world to sacred space. With its stunning architecture and picturesque surroundings, the Handara Gate is a must-visit spot for photos and Instagram-worthy moments.', 'https://www.baliholiday.xyz/blog/-handara-gate-bali-instagram-famous-gateway-to-serenity', 'Banyumala Waterfall', '-8.215594485686836', '115.10189567204543', 'Conclude your journey with a visit to Banyumala Twin Waterfalls. A cascade of small waterfalls converges into a natural pool—a hidden gem in north Bali. Take a refreshing swim in the ice-cold water amidst the jungle backdrop. Capture the beauty of a hundred tiny waterfalls merging into one.', 'https://www.baliholiday.xyz/blog/banyumala-twin-waterfalls-bali-secluded-paradise', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2024-04-05 08:46:42', '2024-04-09 14:17:55', 5),
(5, ' Bedugul Traditional Market', '-8.282198583667604', '115.162296009709', 'First stop: Bedugul Traditional Market (Pasar Candi Kuning). Here, you can experience the lively atmosphere and find a vast array of fresh fruits and vegetables, local snacks, and even grab a filling breakfast', '', 'Munduk Waterfall', '-8.254207637952403', '115.07929833669178', 'Next, head to Munduk Waterfall. Enjoy a scenic walk through the lush rainforest for roughly 20 minutes to arrive at the base of the waterfall. Take in the refreshing sight and sound of the cascading water. Allocate around 1 hour for this stop.\n', '', 'Banjar Hot Springs', '-8.205709196879113', '114.96879701655492', 'Continue the journey to Banjar Hot Springs. Relax and soak in the rejuvenating mineral-rich volcanic waters. This natural hot spring complex offers pools with varying temperatures and some even have waterslides. \n', '', 'Lovina Beach', '-8.160922704837171', '115.02436167488418', 'In the afternoon, travel to Lovina Beach. This black sand beach is known for its calm waves and laid-back atmosphere. Here, you can enjoy some downtime at the beach\n', '', 'Gitgit Waterfall', '-8.187929619307319', '115.13666683854377', 'The last stop is Gitgit Waterfall. Witness the cascading water surrounded by lush greenery. Take a short trek down approximately 400 steps to get a closer look.\n', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2024-05-10 04:59:25', '2024-05-10 04:59:25', 6),
(6, 'Lempuyang Temple (Gates of Heaven)', '-8.3907646', '115.6295156', 'Begin your journey by visiting the iconic Lempuyang Temple, known for its stunning “Gates of Heaven.” Take your time to capture breathtaking photos with the majestic Mount Agung as a backdrop and enjoy the serene, spiritual atmosphere of one of Bali\'s oldest temples.', 'https://www.baliholiday.xyz/blog/exploring-heaven\'s-gate-at-pura-lempuyang-in-bali:-a-must-visit-destination', 'Tirta Gangga Water Palace', '-8.4119359', '115.5875139', 'Afterward, make your way to Tirta Gangga, the beautiful royal water palace with charming fountains, lush gardens, and tranquil koi ponds. Stroll through the grounds, feed the fish, or simply admire the unique Balinese architecture.', 'https://www.baliholiday.xyz/blog/exploring-tirta-gangga:-bali\'s-royal-water-palace', 'Taman Ujung Water Palace ', '-8.4632219', '115.6306234', 'Next, head to Taman Ujung Water Palace, where you’ll find beautiful landscapes and scenic views of the sea. The garden’s serene ponds and historic architecture create a peaceful ambiance perfect for relaxing and taking photos.', 'https://www.baliholiday.xyz/blog/taman-ujung-bali:-a-majestic-water-palace', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2024-11-01 12:33:28', '2024-11-01 12:46:43', 7),
(7, 'Kertha Gosa Pavilion', '-8.535712263129396', '115.40358068367802', 'Kertha Gosa is a historic royal court pavilion located in Klungkung Regency. It showcases traditional Balinese architecture and features intricately painted ceilings that depict vivid scenes from Balinese mythology and moral teachings. This cultural site offers a glimpse into Bali’s justice system during the 18th century and is a must-visit for its artistic and historical significance.', 'https://www.baliholiday.xyz/blog/exploring-heaven\'s-gate-at-pura-lempuyang-in-bali:-a-must-visit-destination', 'Besakih Temple', '-8.373859603770859', '115.45254596654993', 'Known as the \"Mother Temple of Bali,\" Besakih is the largest and most important Hindu temple complex on the island. Nestled on the slopes of Mount Agung, this sprawling site features over 80 smaller temples surrounded by lush greenery and panoramic views. Besakih is a spiritual and cultural hub that represents Bali\'s rich religious heritage.', '', 'Goa Lawah Temple', '-8.55090481639395', '115.46878987196334', 'Goa Lawah, or the Bat Cave Temple, is a sacred coastal site where thousands of bats reside in a natural cave. Revered by the Balinese for its spiritual importance, the temple serves as a gateway between the physical and spiritual worlds. Its unique location near the sea adds to its mystical charm, making it a captivating stop on your journey.', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2025-01-05 06:06:28', '2025-01-05 08:02:42', 8),
(8, 'Jatiluwih Rice Terraces', '-8.37016178805751', '115.13133417986265', 'Recognized as a UNESCO World Heritage site, these expansive rice terraces display Bali’s ancient subak irrigation system in all its glory. The rolling, emerald-green fields cascade across the hills, offering a breathtaking view of traditional Balinese agriculture and a peaceful atmosphere perfect for reflection and photography.', 'https://www.baliholiday.xyz/blog/exploring-heaven\'s-gate-at-pura-lempuyang-in-bali:-a-must-visit-destination', 'Leke Leke Waterfall', '-8.366378169711133', '115.19782148305174', 'Nestled in a lush, forested area of Bali, Leke Leke Waterfall is a serene natural wonder known for its cascading waters and refreshing pools. Surrounded by tropical greenery and rugged rock formations, this hidden gem provides a tranquil escape from busy tourist areas. Its accessible path invites visitors to pause, take a dip, and capture stunning photos of its unspoiled beauty.', 'https://www.baliholiday.xyz/blog/exploring-the-hidden-oasis-of-leke-leke-waterfall-in-bali:-serenity-amidst-nature\'s-beauty', 'Local Cultural Stop & Coffee Plantation', '-8.355183013208844', '115.1512014615391', 'Enhance your journey with an optional visit to a nearby coffee plantation or a quaint local village. Learn about Bali’s unique coffee-making process—including the production of kopi luwak—and immerse yourself in the daily rhythms of Balinese life. This cultural interlude adds a flavorful and insightful dimension to your tour, rounding out the experience with local traditions and tastes.', 'https://www.baliholiday.xyz/blog/a-journey-into-bali-coffee-heritage', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2025-02-05 04:50:04', '2025-02-26 03:44:58', 9),
(9, 'Monkey Forest Ubud', '-8.51936807204329', '115.26056562054148', 'Start your tour with a visit to the Sacred Monkey Forest Sanctuary in Ubud. This lush forest is home to hundreds of long-tailed macaques. As you wander through the forest, you’ll be surrounded by towering trees, ancient temple ruins, and playful monkeys. The sanctuary is not only a haven for these curious creatures but also an important spiritual site for locals. Here, you can enjoy the peaceful ambiance while observing the monkeys in their natural habitat, making it an excellent introduction to Bali’s unique wildlife and culture.', 'https://www.baliholiday.xyz/blog/exploring-the-natural-beauty-and-sacred-monkeys-in-sacred-monkey-forest,-ubud', 'Ubud Market', '-8.507126893138356', '115.2625918246553', 'Next, head to Ubud Market, one of Bali’s most vibrant markets. Here, you can find a wide variety of traditional Balinese goods, including handcrafted jewelry, paintings, textiles, and souvenirs. It\'s an excellent place to explore the local culture and pick up some unique keepsakes. Stroll through the bustling market lanes, engage with friendly vendors, and discover the colorful displays of fruits, spices, and artisan crafts. The market gives you an authentic taste of Bali’s artistic heritage.', 'https://www.baliholiday.xyz/blog/exploring-ubud-market:-a-vibrant-cultural-experience', 'Tegalalang Rice Terraces', '-8.431600893760395', '115.27933505749996', 'After Ubud, visit the famous Tegalalang Rice Terraces, known for their stunning views of lush green landscapes. These terraces are an excellent example of Bali’s traditional subak irrigation system, which has been passed down through generations. As you walk through the terraces, you can learn about the farming process and the importance of rice in Balinese culture. The terraced hills are a photographer’s paradise, offering panoramic views that are perfect for capturing Bali\'s natural beauty.', 'https://www.baliholiday.xyz/blog/tegalalang-rice-terraces:-a-cascading-masterpiece-of-nature-and-tradition', 'Kintamani Volcano View', '-8.2825684132107', '115.36422373554039', 'Continue your tour with a scenic drive to Kintamani for breathtaking views of Mount Batur. This active volcano, surrounded by the stunning Lake Batur, offers one of Bali’s most spectacular landscapes. The area is known for its cool climate and the majestic views of the caldera. You can relax here, take in the scenery, and enjoy a refreshing lunch while gazing at the towering volcano in the distance. This spot is perfect for nature lovers and those looking to experience the beauty of Bali\'s highlands.', 'https://www.baliholiday.xyz/blog/trekking-mount-batur:-witnessing-bali\'s-sunrise-from-the-volcanic-summit', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2025-02-26 04:18:01', '2025-02-26 04:18:01', 10),
(10, 'Bali Museum', '-8.657456586964267', '115.2186238732599', 'Start your day with a visit to the Bali Museum, located in Denpasar. This museum is a treasure trove of Balinese art and culture, showcasing artifacts, historical relics, and traditional crafts that span Bali\'s rich history. As you explore the museum’s exhibits, you’ll gain insight into the island’s history, religion, and customs. The museum’s architecture reflects traditional Balinese styles, adding to the cultural experience. It’s the perfect place to start your city tour and understand the deep cultural roots of Bali.', 'https://www.baliholiday.xyz/blog/bali-museum:-a-deep-dive-into-the-cultural-richness-of-the-island-of-the-gods', 'Agung Jagatnata Temple', '-8.656189086142465', '115.2186390461255', 'Next, head to Agung Jagatnata Temple, an important Hindu temple in Denpasar. Dedicated to the island’s Hindu gods, the temple is known for its magnificent architecture and serene atmosphere. The temple complex is a significant religious site for locals and offers visitors a glimpse into the spiritual practices of the Balinese people. The intricate stone carvings and beautiful gates make this a peaceful yet awe-inspiring stop on your tour.', 'https://www.baliholiday.xyz/blog/pura-jagatnatha-denpasar:-an-insight-into-bali%E2%80%99s-sacred-hindu-temple', 'Pasar Badung ', '-8.656439717736017', '115.21243552134196', 'After the temple, visit Pasar Badung, Bali’s largest traditional market, located in the heart of Denpasar. This bustling market is an authentic experience where you can find everything from fresh produce to spices, textiles, and local handicrafts. Walking through the market, you’ll see local life in full swing, with vendors selling a variety of goods and offering a true taste of Bali’s daily life. It’s an ideal place to experience the local culture and pick up some unique souvenirs.', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2025-02-26 05:21:00', '2025-02-26 05:21:00', 11),
(11, 'Mertasari Beach, Sanur', '-8.712743897000907', '115.25065815582117', 'Your adventure begins at Mertasari Beach in Sanur—a serene coastal gem known for its golden sands, calm turquoise waters, and tranquil vibe. This picturesque departure point offers easy access to Bali’s prime fishing grounds while providing a peaceful escape from crowds. Families and anglers alike will appreciate the shaded shoreline, local warungs (eateries), and hassle-free parking. After your fishing expedition, return here to unwind or explore nearby beachside attractions. Mertasari sets the perfect backdrop for launching your Balinese sea adventure!', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '', '2025-03-18 06:30:58', '2025-03-25 16:57:28', 12);

